package com.oneil.wellness.walkplanner.activity;
import jakarta.persistence.*;import java.time.*;import java.util.*;
@Entity @Table(name="walk_activity") public class WalkActivity{
 @Id private UUID id;@Column(name="recommendation_history_id")private UUID recommendationHistoryId;@Column(name="opportunity_start",nullable=false)private OffsetDateTime opportunityStart;@Column(name="opportunity_end",nullable=false)private OffsetDateTime opportunityEnd;@Enumerated(EnumType.STRING)@Column(name="activity_status",nullable=false)private ActivityStatus activityStatus;@Column(name="actual_start")private OffsetDateTime actualStart;@Column(name="actual_end")private OffsetDateTime actualEnd;@Column(name="duration_minutes")private Integer durationMinutes;@Enumerated(EnumType.STRING)@Column(name="perceived_quality")private PerceivedQuality perceivedQuality;@Column(length=1000)private String notes;@Enumerated(EnumType.STRING)@Column(nullable=false)private ActivitySource source;@Column(name="created_at",nullable=false)private Instant createdAt;@Column(name="updated_at",nullable=false)private Instant updatedAt;
 protected WalkActivity(){} public static WalkActivity start(WalkRequest r,Instant now){var v=new WalkActivity();v.id=UUID.randomUUID();v.recommendationHistoryId=r.recommendationHistoryId();v.opportunityStart=r.opportunityStart();v.opportunityEnd=r.opportunityEnd();v.activityStatus=ActivityStatus.ACTIVE;v.actualStart=OffsetDateTime.ofInstant(now,r.opportunityStart().getOffset());v.source=r.source()==null?ActivitySource.DASHBOARD:r.source();v.createdAt=now;v.updatedAt=now;return v;}public static WalkActivity manual(ManualWalkRequest r,Instant now){var v=new WalkActivity();v.id=UUID.randomUUID();v.opportunityStart=r.actualStart();v.actualStart=r.actualStart();v.actualEnd=r.actualStart().plusMinutes(r.durationMinutes());v.opportunityEnd=v.actualEnd;v.durationMinutes=r.durationMinutes();v.activityStatus=ActivityStatus.COMPLETED;v.perceivedQuality=r.perceivedQuality();v.notes=clean(r.notes());v.source=ActivitySource.MANUAL_ENTRY;v.createdAt=now;v.updatedAt=now;return v;}public void complete(CompleteWalkRequest r,Instant now,int max){int duration=r.durationMinutes()!=null?r.durationMinutes():(int)Duration.between(actualStart.toInstant(),now).toMinutes();if(duration<1||duration>max)throw new IllegalArgumentException("Walk duration must be between 1 and "+max+" minutes.");durationMinutes=duration;actualEnd=actualStart.plusMinutes(duration);activityStatus=Boolean.TRUE.equals(r.partiallyCompleted())?ActivityStatus.PARTIALLY_COMPLETED:ActivityStatus.COMPLETED;perceivedQuality=r.perceivedQuality();notes=clean(r.notes());updatedAt=now;}private static String clean(String v){if(v==null||v.isBlank())return null;String s=v.strip();if(s.length()>1000)throw new IllegalArgumentException("Notes must be 1000 characters or fewer.");return s;}public UUID getId(){return id;}public UUID getRecommendationHistoryId(){return recommendationHistoryId;}public OffsetDateTime getOpportunityStart(){return opportunityStart;}public OffsetDateTime getOpportunityEnd(){return opportunityEnd;}public ActivityStatus getActivityStatus(){return activityStatus;}public OffsetDateTime getActualStart(){return actualStart;}public OffsetDateTime getActualEnd(){return actualEnd;}public Integer getDurationMinutes(){return durationMinutes;}public PerceivedQuality getPerceivedQuality(){return perceivedQuality;}public String getNotes(){return notes;}public ActivitySource getSource(){return source;}public Instant getCreatedAt(){return createdAt;}public Instant getUpdatedAt(){return updatedAt;}}
